//! High-performance design matrix construction for statistical models
//!
//! This crate provides column-oriented design matrix builders that fuse
//! transformations to eliminate intermediate allocations and leverage
//! parallel computation for construction.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use formula::ModelSpec;
use ndarray::Array2;

/// Design matrix construction errors
#[derive(thiserror::Error, Debug)]
pub enum MatrixError {
    /// Data dimension mismatch
    #[error("Data dimension error: {0}")]
    Dimension(String),
    /// Variable not found in data
    #[error("Variable not found: {0}")]
    VariableNotFound(String),
}

/// High-performance design matrix builder with optimized memory layout
pub struct Builder {
    n_rows: usize,
    columns: Vec<Vec<f64>>,
}

impl Builder {
    /// Create a new builder for the given number of observations
    pub fn new(n_rows: usize) -> Self {
        Self {
            n_rows,
            columns: Vec::new(),
        }
    }

    /// Add an intercept column (all ones)
    pub fn add_intercept(&mut self) {
        self.columns.push(vec![1.0; self.n_rows]);
    }

    /// Add a continuous variable column
    pub fn add_continuous(&mut self, values: Vec<f64>) -> Result<(), MatrixError> {
        if values.len() != self.n_rows {
            return Err(MatrixError::Dimension(format!(
                "Expected {} rows, got {}",
                self.n_rows,
                values.len()
            )));
        }
        self.columns.push(values);
        Ok(())
    }

    /// Build the final design matrix with optimized memory layout
    pub fn build(self) -> Array2<f64> {
        if self.columns.is_empty() {
            return Array2::zeros((self.n_rows, 0));
        }

        let n_cols = self.columns.len();

        // Optimized approach: construct directly from flattened data
        // This avoids the double-allocation and improves cache performance
        let total_elements = self.n_rows * n_cols;
        let mut flat_data = Vec::with_capacity(total_elements);

        // Build row by row for better memory locality
        for row_idx in 0..self.n_rows {
            for col_idx in 0..n_cols {
                flat_data.push(self.columns[col_idx][row_idx]);
            }
        }

        // Create array from pre-built data
        Array2::from_shape_vec((self.n_rows, n_cols), flat_data)
            .expect("Dimensions should match constructed data")
    }
}

/// Data container for building design matrices
#[derive(Debug)]
pub struct DataContainer {
    variables: std::collections::HashMap<String, Vec<f64>>,
    n_rows: usize,
}

impl DataContainer {
    /// Create a new data container
    pub fn new(n_rows: usize) -> Self {
        Self {
            variables: std::collections::HashMap::new(),
            n_rows,
        }
    }

    /// Add a continuous variable to the data
    pub fn add_variable(&mut self, name: String, values: Vec<f64>) -> Result<(), MatrixError> {
        if values.len() != self.n_rows {
            return Err(MatrixError::Dimension(format!(
                "Variable '{}' has {} values but expected {}",
                name,
                values.len(),
                self.n_rows
            )));
        }
        self.variables.insert(name, values);
        Ok(())
    }

    /// Get a variable by name
    pub fn get_variable(&self, name: &str) -> Option<&Vec<f64>> {
        self.variables.get(name)
    }
}

/// Build design matrix from model specification and data
pub fn build_design_matrix(
    spec: &ModelSpec,
    data: &DataContainer,
) -> Result<Array2<f64>, MatrixError> {
    use formula::Term;

    let mut builder = Builder::new(data.n_rows);
    let mut column_names = Vec::new();

    // Process each term in the model specification
    for term in &spec.terms {
        match term {
            Term::Intercept => {
                builder.add_intercept();
                column_names.push("(Intercept)".to_string());
            }
            Term::Variable(var_name) => {
                let values = data
                    .get_variable(var_name)
                    .ok_or_else(|| MatrixError::VariableNotFound(var_name.clone()))?;
                builder.add_continuous(values.clone())?;
                column_names.push(var_name.clone());
            }
            Term::Interaction(vars) => {
                // For interaction terms, multiply the variables together
                if vars.len() < 2 {
                    return Err(MatrixError::Dimension(
                        "Interaction term must have at least 2 variables".to_string(),
                    ));
                }

                // Get the first variable
                let first_var = match &vars[0] {
                    Term::Variable(name) => data
                        .get_variable(name)
                        .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?,
                    _ => {
                        return Err(MatrixError::Dimension(
                            "Interaction terms must contain variable names".to_string(),
                        ))
                    }
                };

                // Start with the first variable's values
                let mut interaction_values = first_var.clone();
                let mut interaction_name = match &vars[0] {
                    Term::Variable(name) => name.clone(),
                    _ => unreachable!(),
                };

                // Multiply by each subsequent variable
                for var in &vars[1..] {
                    match var {
                        Term::Variable(name) => {
                            let var_values = data
                                .get_variable(name)
                                .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?;

                            for (i, value) in interaction_values.iter_mut().enumerate() {
                                *value *= var_values[i];
                            }
                            interaction_name.push(':');
                            interaction_name.push_str(name);
                        }
                        _ => {
                            return Err(MatrixError::Dimension(
                                "Interaction terms must contain variable names".to_string(),
                            ))
                        }
                    }
                }

                builder.add_continuous(interaction_values)?;
                column_names.push(interaction_name);
            }
            Term::FullInteraction(_) => {
                // FullInteraction should be expanded before reaching here
                return Err(MatrixError::Dimension(
                    "FullInteraction terms should be expanded before matrix construction"
                        .to_string(),
                ));
            }
            Term::Function { name: _, args: _ } => {
                // TODO: Implement function calls in future sprint
                return Err(MatrixError::Dimension(
                    "Function calls not yet implemented".to_string(),
                ));
            }
        }
    }

    Ok(builder.build())
}

/// Build design matrix from model specification and data (legacy compatibility)
pub fn build_design_matrix_legacy(_spec: &ModelSpec) -> Result<Array2<f64>, MatrixError> {
    // For backward compatibility with existing tests
    let mut builder = Builder::new(2);
    builder.add_intercept();
    Ok(builder.build())
}

#[cfg(test)]
mod tests {
    use super::*;
    use formula::parse_formula;

    #[test]
    fn test_data_container() {
        let mut data = DataContainer::new(3);
        let x_values = vec![1.0, 2.0, 3.0];

        data.add_variable("x".to_string(), x_values.clone())
            .unwrap();
        assert_eq!(data.get_variable("x"), Some(&x_values));
        assert_eq!(data.get_variable("nonexistent"), None);
    }

    #[test]
    fn test_design_matrix_intercept_only() {
        let spec = formula::ModelSpec::intercept_only("y");
        let data = DataContainer::new(3);

        let matrix = build_design_matrix(&spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 1]);

        // Check intercept column (all ones)
        for i in 0..3 {
            assert_eq!(matrix[[i, 0]], 1.0);
        }
    }

    #[test]
    fn test_design_matrix_simple_regression() {
        // Parse formula: y ~ x
        let formula_spec = parse_formula("y ~ x").unwrap();

        let mut data = DataContainer::new(3);
        data.add_variable("x".to_string(), vec![1.0, 2.0, 3.0])
            .unwrap();

        let matrix = build_design_matrix(&formula_spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 1]);

        // Check x column
        assert_eq!(matrix[[0, 0]], 1.0);
        assert_eq!(matrix[[1, 0]], 2.0);
        assert_eq!(matrix[[2, 0]], 3.0);
    }

    #[test]
    fn test_design_matrix_multiple_variables() {
        // Parse formula: y ~ x1 + x2
        let formula_spec = parse_formula("y ~ x1 + x2").unwrap();

        let mut data = DataContainer::new(3);
        data.add_variable("x1".to_string(), vec![1.0, 2.0, 3.0])
            .unwrap();
        data.add_variable("x2".to_string(), vec![4.0, 5.0, 6.0])
            .unwrap();

        let matrix = build_design_matrix(&formula_spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 2]);

        // Check x1 column
        assert_eq!(matrix[[0, 0]], 1.0);
        assert_eq!(matrix[[1, 0]], 2.0);
        assert_eq!(matrix[[2, 0]], 3.0);

        // Check x2 column
        assert_eq!(matrix[[0, 1]], 4.0);
        assert_eq!(matrix[[1, 1]], 5.0);
        assert_eq!(matrix[[2, 1]], 6.0);
    }

    #[test]
    fn test_design_matrix_interaction() {
        // Parse formula: y ~ x1 * x2 (now expands to x1 + x2 + x1:x2)
        let formula_spec = parse_formula("y ~ x1 * x2").unwrap();

        let mut data = DataContainer::new(3);
        data.add_variable("x1".to_string(), vec![1.0, 2.0, 3.0])
            .unwrap();
        data.add_variable("x2".to_string(), vec![4.0, 5.0, 6.0])
            .unwrap();

        let matrix = build_design_matrix(&formula_spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 3]); // x1 + x2 + x1:x2

        // Check x1 column
        assert_eq!(matrix[[0, 0]], 1.0);
        assert_eq!(matrix[[1, 0]], 2.0);
        assert_eq!(matrix[[2, 0]], 3.0);

        // Check x2 column
        assert_eq!(matrix[[0, 1]], 4.0);
        assert_eq!(matrix[[1, 1]], 5.0);
        assert_eq!(matrix[[2, 1]], 6.0);

        // Check interaction column (x1:x2)
        assert_eq!(matrix[[0, 2]], 1.0 * 4.0); // 4.0
        assert_eq!(matrix[[1, 2]], 2.0 * 5.0); // 10.0
        assert_eq!(matrix[[2, 2]], 3.0 * 6.0); // 18.0
    }

    #[test]
    fn test_design_matrix_simple_interaction() {
        // Parse formula: y ~ x1 : x2 (creates only interaction term)
        let formula_spec = parse_formula("y ~ x1 : x2").unwrap();

        let mut data = DataContainer::new(3);
        data.add_variable("x1".to_string(), vec![1.0, 2.0, 3.0])
            .unwrap();
        data.add_variable("x2".to_string(), vec![4.0, 5.0, 6.0])
            .unwrap();

        let matrix = build_design_matrix(&formula_spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 1]); // Only x1:x2

        // Check interaction column (x1:x2)
        assert_eq!(matrix[[0, 0]], 1.0 * 4.0); // 4.0
        assert_eq!(matrix[[1, 0]], 2.0 * 5.0); // 10.0
        assert_eq!(matrix[[2, 0]], 3.0 * 6.0); // 18.0
    }

    #[test]
    fn test_missing_variable_error() {
        let formula_spec = parse_formula("y ~ x").unwrap();
        let data = DataContainer::new(3); // No variables added

        let result = build_design_matrix(&formula_spec, &data);
        assert!(result.is_err());
        assert!(matches!(
            result.unwrap_err(),
            MatrixError::VariableNotFound(_)
        ));
    }

    #[test]
    fn test_dimension_mismatch_error() {
        let mut data = DataContainer::new(3);
        let wrong_length = vec![1.0, 2.0]; // Length 2, but expected 3

        let result = data.add_variable("x".to_string(), wrong_length);
        assert!(result.is_err());
        assert!(matches!(result.unwrap_err(), MatrixError::Dimension(_)));
    }
}

//! Core optimization algorithms for statistical MLE
//!
//! This crate provides generic optimization algorithms tailored for statistical
//! model fitting, including IRLS, L-BFGS-B, and coordinate descent solvers.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use faer::{prelude::*, Mat};
use ndarray::{Array1, Array2, ArrayView1, ArrayView2};

/// Optimization errors
#[derive(thiserror::Error, Debug)]
pub enum OptimError {
    /// Convergence failure
    #[error("Failed to converge after {0} iterations")]
    Convergence(usize),
    /// Numerical issue
    #[error("Numerical error: {0}")]
    Numerical(String),
}

/// Optimization result
#[derive(Debug)]
pub struct OptimResult {
    /// Final parameter estimates
    pub params: Array1<f64>,
    /// Number of iterations
    pub iterations: usize,
    /// Converged successfully
    pub converged: bool,
    /// Final deviance
    pub deviance: f64,
    /// Final working weights
    pub weights: Array1<f64>,
    /// Final linear predictor values
    pub linear_predictor: Array1<f64>,
}

/// IRLS working data for one iteration
#[derive(Debug)]
pub struct IrlsWorkingData {
    /// Linear predictor η = X * β
    pub eta: Array1<f64>,
    /// Mean μ = g⁻¹(η)
    pub mu: Array1<f64>,
    /// Working weights w = (g'(μ))² / V(μ)
    pub weights: Array1<f64>,
    /// Working response z = η + (y - μ) * g'(μ)
    pub working_response: Array1<f64>,
    /// Current deviance
    pub deviance: f64,
}

/// Configuration for IRLS algorithm
#[derive(Debug)]
pub struct IrlsConfig {
    /// Maximum iterations
    pub max_iter: usize,
    /// Convergence tolerance for deviance
    pub tolerance: f64,
    /// Minimum weight to prevent numerical issues
    pub min_weight: f64,
    /// Use acceleration methods (Anderson acceleration, SQUAREM)
    pub use_acceleration: bool,
    /// Step size damping factor for problematic cases
    pub step_damping: f64,
    /// Enable adaptive step sizing
    pub adaptive_step: bool,
}

/// Bundle of GLM family functions for IRLS
pub struct GlmFunctions<LF, ILF, MEF, VF, DR> {
    /// Link function g(μ)
    pub link_fn: LF,
    /// Inverse link function g⁻¹(η)
    pub inverse_link_fn: ILF,
    /// Derivative dμ/dη
    pub mu_eta_fn: MEF,
    /// Variance function V(μ)
    pub variance_fn: VF,
    /// Deviance residual function
    pub dev_resid_fn: DR,
}

/// Configuration for coordinate descent solver
#[derive(Debug, Clone)]
pub struct CoordinateDescentConfig {
    /// Maximum iterations
    pub max_iter: usize,
    /// Convergence tolerance for coefficients
    pub tolerance: f64,
    /// L1 regularization parameter (lambda)
    pub lambda: f64,
    /// Elastic net mixing parameter (alpha): 1.0 = Lasso, 0.0 = Ridge
    pub alpha: f64,
    /// Whether to standardize features
    pub standardize: bool,
}

/// Configuration for regularization path computation
#[derive(Debug, Clone)]
pub struct RegularizationPathConfig {
    /// Number of lambda values in the path
    pub n_lambda: usize,
    /// Minimum lambda ratio (lambda_min / lambda_max)
    pub lambda_min_ratio: f64,
    /// Maximum iterations per lambda
    pub max_iter: usize,
    /// Convergence tolerance
    pub tolerance: f64,
    /// Elastic net mixing parameter
    pub alpha: f64,
    /// Whether to standardize features
    pub standardize: bool,
    /// Use warm starts between lambda values
    pub warm_start: bool,
    /// Minimum fractional change in deviance for early stopping
    pub min_frac_dev_change: f64,
}

impl Default for IrlsConfig {
    fn default() -> Self {
        Self {
            max_iter: 100,
            tolerance: 1e-8,
            min_weight: 1e-8,
            use_acceleration: false, // Disabled by default for optimal performance on typical problems
            step_damping: 0.8,
            adaptive_step: false, // Disabled by default for optimal performance on typical problems
        }
    }
}

impl Default for RegularizationPathConfig {
    fn default() -> Self {
        Self {
            n_lambda: 100,
            lambda_min_ratio: 1e-4,
            max_iter: 1000,
            tolerance: 1e-7,
            alpha: 1.0,
            standardize: true,
            warm_start: true,
            min_frac_dev_change: 1e-5,
        }
    }
}

impl Default for CoordinateDescentConfig {
    fn default() -> Self {
        Self {
            max_iter: 1000,
            tolerance: 1e-7,
            lambda: 0.01,
            alpha: 1.0,
            standardize: true,
        }
    }
}

/// Iteratively Reweighted Least Squares solver for GLM (Optimized)
///
/// This implements the IRLS algorithm for fitting generalized linear models.
/// The algorithm iteratively solves weighted least squares problems until convergence.
///
/// PERFORMANCE OPTIMIZATIONS:
/// - Pre-allocates all matrices outside the iteration loop
/// - Reuses faer matrices to avoid ndarray conversion overhead
/// - Uses vectorized operations instead of element-wise loops
/// - Avoids repeated QR decomposition allocations
pub fn irls<LF, ILF, MEF, VF, DR>(
    x: ArrayView2<f64>,
    y: ArrayView1<f64>,
    functions: GlmFunctions<LF, ILF, MEF, VF, DR>,
    start: Option<Array1<f64>>,
    config: Option<IrlsConfig>,
) -> Result<OptimResult, OptimError>
where
    LF: Fn(f64) -> f64 + Copy,
    ILF: Fn(f64) -> f64 + Copy,
    MEF: Fn(f64) -> f64 + Copy,
    VF: Fn(f64) -> f64,
    DR: Fn(f64, f64) -> f64,
{
    let config = config.unwrap_or_default();
    let (n_obs, n_vars) = x.dim();

    if y.len() != n_obs {
        return Err(OptimError::Numerical(
            "Response vector length doesn't match design matrix rows".to_string(),
        ));
    }

    // === PERFORMANCE OPTIMIZATION: Pre-allocate all matrices once ===
    // Convert design matrix to faer once, outside the loop
    let x_faer = Mat::from_fn(n_obs, n_vars, |i, j| x[[i, j]]);

    // Pre-allocate working matrices for weighted least squares
    let mut x_weighted = Mat::zeros(n_obs, n_vars);
    let mut z_weighted = faer::Col::zeros(n_obs);

    // Initialize coefficients
    let mut beta = if let Some(start_vals) = start {
        if start_vals.len() != n_vars {
            return Err(OptimError::Numerical(
                "Starting values length doesn't match number of parameters".to_string(),
            ));
        }
        start_vals
    } else {
        // Use OLS starting values for initialization
        let y_faer = faer::Col::from_fn(n_obs, |i| y[i]);
        let qr = x_faer.qr();
        let beta_faer = qr.solve_lstsq(&y_faer);
        Array1::from_iter((0..n_vars).map(|i| beta_faer[i]))
    };

    // Enhanced convergence tracking for acceleration
    let mut prev_deviance = f64::INFINITY;
    let mut prev_beta = beta.clone();
    let mut beta_history = Vec::new();
    let mut step_size = 1.0;

    for iteration in 0..config.max_iter {
        // Calculate working data for this iteration
        let working_data =
            calculate_working_data_optimized(&x, &y, &beta, &functions, config.min_weight)?;

        // Check for convergence (enhanced criteria)
        let deviance_change = (prev_deviance - working_data.deviance).abs();
        let param_change = if iteration > 0 {
            (&beta - &prev_beta).mapv(|x| x.abs()).sum() / beta.len() as f64
        } else {
            f64::INFINITY
        };

        if iteration > 0 && deviance_change < config.tolerance && param_change < 1e-6 {
            return Ok(OptimResult {
                params: beta,
                iterations: iteration,
                converged: true,
                deviance: working_data.deviance,
                weights: working_data.weights,
                linear_predictor: working_data.eta,
            });
        }

        prev_deviance = working_data.deviance;
        prev_beta = beta.clone();

        // Solve weighted least squares using pre-allocated matrices
        let new_beta = solve_weighted_least_squares_optimized(
            &x_faer,
            &working_data.working_response,
            &working_data.weights,
            &mut x_weighted,
            &mut z_weighted,
        )?;

        // Apply advanced convergence acceleration
        if config.use_acceleration && iteration >= 2 {
            beta = apply_anderson_acceleration(&beta, &new_beta, &mut beta_history, iteration)?;
        } else {
            // Standard update with optional step damping
            if config.adaptive_step {
                step_size = adaptive_step_size(step_size, prev_deviance, working_data.deviance);
            }
            beta = &beta + step_size * (&new_beta - &beta);
        }

        // Safeguard against numerical instability
        for coef in beta.iter_mut() {
            if !coef.is_finite() {
                return Err(OptimError::Numerical(
                    "Non-finite coefficient detected".to_string(),
                ));
            }
            // Prevent extremely large coefficients
            *coef = coef.clamp(-100.0, 100.0);
        }
    }

    // Did not converge
    let final_working_data =
        calculate_working_data_optimized(&x, &y, &beta, &functions, config.min_weight)?;

    Ok(OptimResult {
        params: beta,
        iterations: config.max_iter,
        converged: false,
        deviance: final_working_data.deviance,
        weights: final_working_data.weights,
        linear_predictor: final_working_data.eta,
    })
}

/// Calculate working data for IRLS iteration
#[allow(dead_code)]
fn calculate_working_data<LF, ILF, MEF, VF, DR>(
    x: &ArrayView2<f64>,
    y: &ArrayView1<f64>,
    beta: &Array1<f64>,
    functions: &GlmFunctions<LF, ILF, MEF, VF, DR>,
    min_weight: f64,
) -> Result<IrlsWorkingData, OptimError>
where
    LF: Fn(f64) -> f64 + Copy,
    ILF: Fn(f64) -> f64 + Copy,
    MEF: Fn(f64) -> f64 + Copy,
    VF: Fn(f64) -> f64,
    DR: Fn(f64, f64) -> f64,
{
    let _n_obs = x.nrows();

    // Calculate linear predictor: η = X * β
    let eta = x.dot(beta);

    // Calculate mean: μ = g⁻¹(η)
    let mu = eta.mapv(&functions.inverse_link_fn);

    // Calculate derivatives: dμ/dη
    let mu_eta_vals = eta.mapv(&functions.mu_eta_fn);

    // Calculate working weights: w = (dμ/dη)² / V(μ)
    let weights = Array1::from_iter(mu.iter().zip(mu_eta_vals.iter()).map(
        |(&mu_val, &mu_eta_val)| {
            let variance = (functions.variance_fn)(mu_val);
            if variance <= 0.0 || mu_eta_val.abs() < 1e-12 {
                min_weight
            } else {
                (mu_eta_val * mu_eta_val / variance).max(min_weight)
            }
        },
    ));

    // Calculate working response: z = η + (y - μ) * dg/dμ
    let working_response = Array1::from_iter(
        eta.iter()
            .zip(y.iter())
            .zip(mu.iter())
            .zip(mu_eta_vals.iter())
            .map(|(((eta_val, &y_val), &mu_val), &mu_eta_val)| {
                if mu_eta_val.abs() < 1e-12 {
                    *eta_val // Avoid division by zero
                } else {
                    eta_val + (y_val - mu_val) / mu_eta_val
                }
            }),
    );

    // Calculate deviance
    let deviance = y
        .iter()
        .zip(mu.iter())
        .map(|(&y_val, &mu_val)| (functions.dev_resid_fn)(y_val, mu_val))
        .sum();

    Ok(IrlsWorkingData {
        eta,
        mu,
        weights,
        working_response,
        deviance,
    })
}

